// src/rate_limit.rs (extend existing file)
use std::time::{Duration, Instant};
use tracing::{debug, trace, instrument};

/// Token bucket rate limiter with burst capacity
/// 
/// Allows bursts up to capacity, then rate-limits to refill_rate.
/// Tokens refill continuously based on elapsed time.
#[derive(Debug)]
pub struct TokenBucket {
    /// Maximum tokens (burst capacity)
    capacity: usize,
    /// Current available tokens (fractional for smooth refill)
    tokens: f64,
    /// Tokens added per second
    refill_rate: f64,
    /// Last time we calculated token refill
    last_refill: Instant,
}

impl TokenBucket {
    /// Create a new token bucket
    /// 
    /// # Arguments
    /// * \`capacity\` - Maximum burst size
    /// * \`refill_rate\` - Tokens per second to refill
    #[instrument]
    pub fn new(capacity: usize, refill_rate: f64) -> Self {
        debug!(
            capacity = %capacity,
            refill_rate = %refill_rate,
            "Token bucket created"
        );
        Self {
            capacity,
            tokens: capacity as f64, // Start full
            refill_rate,
            last_refill: Instant::now(),
        }
    }

    /// Create from operations per second with specified burst
    pub fn from_rate(ops_per_second: f64, burst_size: usize) -> Self {
        Self::new(burst_size, ops_per_second)
    }

    /// Refill tokens based on elapsed time
    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill).as_secs_f64();
        self.tokens = (self.tokens + elapsed * self.refill_rate)
            .min(self.capacity as f64);
        self.last_refill = now;
    }

    /// Check if a token is available (non-blocking)
    pub fn check(&mut self) -> bool {
        self.refill();
        self.tokens >= 1.0
    }

    /// Try to consume a token (non-blocking)
    /// Returns true if successful, false if no tokens available
    pub fn try_acquire(&mut self) -> bool {
        self.refill();
        if self.tokens >= 1.0 {
            self.tokens -= 1.0;
            trace!(remaining = %self.tokens, "Token acquired");
            true
        } else {
            trace!(available = %self.tokens, "No tokens available");
            false
        }
    }

    /// Try to consume multiple tokens at once
    pub fn try_acquire_many(&mut self, count: usize) -> bool {
        self.refill();
        let needed = count as f64;
        if self.tokens >= needed {
            self.tokens -= needed;
            trace!(acquired = %count, remaining = %self.tokens, "Tokens acquired");
            true
        } else {
            trace!(
                requested = %count,
                available = %self.tokens,
                "Insufficient tokens"
            );
            false
        }
    }

    /// Wait until a token is available (async)
    #[instrument(skip(self))]
    pub async fn wait(&mut self) {
        self.refill();
        if self.tokens < 1.0 {
            let needed = 1.0 - self.tokens;
            let wait_secs = needed / self.refill_rate;
            let wait_time = Duration::from_secs_f64(wait_secs);
            trace!(wait_ms = %wait_time.as_millis(), "Waiting for token");
            tokio::time::sleep(wait_time).await;
            self.refill();
        }
        self.tokens -= 1.0;
    }

    /// Time until a token is available
    pub fn time_until_token(&mut self) -> Duration {
        self.refill();
        if self.tokens >= 1.0 {
            Duration::ZERO
        } else {
            let needed = 1.0 - self.tokens;
            Duration::from_secs_f64(needed / self.refill_rate)
        }
    }

    /// Get current available tokens (may be fractional)
    pub fn available(&mut self) -> f64 {
        self.refill();
        self.tokens
    }

    /// Get capacity
    pub fn capacity(&self) -> usize {
        self.capacity
    }

    /// Get refill rate (tokens per second)
    pub fn refill_rate(&self) -> f64 {
        self.refill_rate
    }

    /// Reset to full capacity
    pub fn reset(&mut self) {
        self.tokens = self.capacity as f64;
        self.last_refill = Instant::now();
        debug!("Token bucket reset to full");
    }
}

/// Robot mode token bucket status
#[derive(serde::Serialize)]
pub struct TokenBucketStatus {
    pub available_tokens: f64,
    pub capacity: usize,
    pub refill_rate: f64,
    pub wait_ms: u64,
}

impl TokenBucket {
    /// Get status for robot mode output
    pub fn status(&mut self) -> TokenBucketStatus {
        self.refill();
        TokenBucketStatus {
            available_tokens: self.tokens,
            capacity: self.capacity,
            refill_rate: self.refill_rate,
            wait_ms: self.time_until_token().as_millis() as u64,
        }
    }
}
