#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_initial_burst() {
        let mut bucket = TokenBucket::new(5, 1.0);
        // Should allow 5 immediate operations
        for _ in 0..5 {
            assert!(bucket.try_acquire());
        }
        // 6th should fail
        assert!(!bucket.try_acquire());
    }

    #[test]
    fn test_refill() {
        let mut bucket = TokenBucket::new(5, 10.0); // 10 tokens/sec

        // Exhaust tokens
        for _ in 0..5 {
            bucket.try_acquire();
        }
        assert!(!bucket.check());

        // Wait for refill (100ms = 1 token at 10/sec)
        std::thread::sleep(Duration::from_millis(150));
        assert!(bucket.check());
        assert!(bucket.try_acquire());
    }

    #[test]
    fn test_partial_refill() {
        let mut bucket = TokenBucket::new(10, 100.0); // 100 tokens/sec

        // Use all tokens
        for _ in 0..10 {
            bucket.try_acquire();
        }

        // Wait 50ms = 5 tokens
        std::thread::sleep(Duration::from_millis(55));
        let available = bucket.available();
        assert!(available >= 4.5 && available <= 6.0);
    }

    #[test]
    fn test_acquire_many() {
        let mut bucket = TokenBucket::new(10, 1.0);

        assert!(bucket.try_acquire_many(5));
        assert!(bucket.try_acquire_many(3));
        assert!(!bucket.try_acquire_many(5)); // Only 2 left
        assert!(bucket.try_acquire_many(2));
        assert!(!bucket.try_acquire());
    }

    #[test]
    fn test_capacity_cap() {
        let mut bucket = TokenBucket::new(5, 100.0);
        std::thread::sleep(Duration::from_millis(100)); // Would add 10 tokens

        let available = bucket.available();
        assert_eq!(available, 5.0); // Capped at capacity
    }

    #[tokio::test]
    async fn test_async_wait() {
        let mut bucket = TokenBucket::new(1, 100.0); // Fast refill
        bucket.try_acquire(); // Exhaust

        let start = Instant::now();
        bucket.wait().await;
        let elapsed = start.elapsed();

        // Should have waited ~10ms (1/100 sec)
        assert!(elapsed >= Duration::from_millis(5));
        assert!(elapsed < Duration::from_millis(50));
    }

    #[test]
    fn test_reset() {
        let mut bucket = TokenBucket::new(5, 1.0);
        for _ in 0..5 {
            bucket.try_acquire();
        }
        assert!(!bucket.check());

        bucket.reset();
        assert!(bucket.check());
        assert_eq!(bucket.available(), 5.0);
    }
}
