fn key_filled(&self, key: u8, color: &str) {
    let mut text = Text::new("");
    text.append_styled("  ✓ ", Style::new().bold().color(self.theme.success.clone()));
    text.append_styled("Key ", self.theme.label.clone());
    text.append_styled(&format!("{}", key), self.theme.key_index.clone());
    text.append_styled(" filled with ", self.theme.label.clone());

    // Try to display color with actual color if valid hex
    if let Some(parsed_color) = parse_hex_color(color) {
        text.append_styled(color, Style::new().color(parsed_color));
    } else {
        text.append_styled(color, self.theme.value.clone());
    }

    self.console.print_text(&text);
}

/// Parse hex color string to rich_rust Color
fn parse_hex_color(hex: &str) -> Option<Color> {
    Color::parse(hex).ok()
}
