// src/gestures.rs
use std::collections::HashMap;
use std::time::{Duration, Instant};
use tracing::{debug, trace, info, warn, instrument, span, Level};

/// Configuration for gesture timing thresholds
#[derive(Debug, Clone)]
pub struct GestureConfig {
    /// Time threshold for long-press detection (default: 800ms)
    pub long_press_threshold: Duration,
    /// Window for detecting double-tap (default: 300ms)
    pub double_tap_window: Duration,
    /// Interval between hold tick events (default: 100ms)
    pub hold_tick_interval: Duration,
}

impl Default for GestureConfig {
    fn default() -> Self {
        Self {
            long_press_threshold: Duration::from_millis(800),
            double_tap_window: Duration::from_millis(300),
            hold_tick_interval: Duration::from_millis(100),
        }
    }
}

/// Raw button event from device
#[derive(Debug, Clone)]
pub struct RawKeyEvent {
    pub key: u8,
    pub pressed: bool,
    pub timestamp: Instant,
}

/// Detected gesture types
#[derive(Debug, Clone)]
pub enum Gesture {
    /// Quick press and release
    Tap { key: u8 },
    /// Two taps in quick succession
    DoubleTap { key: u8, interval: Duration },
    /// Press held past threshold then released
    LongPress { key: u8, duration: Duration },
    /// Key is being held - initial event
    HoldStart { key: u8 },
    /// Periodic tick while key is held
    HoldTick { key: u8, held_for: Duration },
    /// Key released after being held
    HoldEnd { key: u8, total: Duration },
}

impl Gesture {
    pub fn key(&self) -> u8 {
        match self {
            Gesture::Tap { key } => *key,
            Gesture::DoubleTap { key, .. } => *key,
            Gesture::LongPress { key, .. } => *key,
            Gesture::HoldStart { key } => *key,
            Gesture::HoldTick { key, .. } => *key,
            Gesture::HoldEnd { key, .. } => *key,
        }
    }

    pub fn gesture_type(&self) -> &'static str {
        match self {
            Gesture::Tap { .. } => "tap",
            Gesture::DoubleTap { .. } => "double_tap",
            Gesture::LongPress { .. } => "long_press",
            Gesture::HoldStart { .. } => "hold_start",
            Gesture::HoldTick { .. } => "hold_tick",
            Gesture::HoldEnd { .. } => "hold_end",
        }
    }
}

/// Per-key state for gesture detection
#[derive(Debug, Default)]
struct KeyGestureState {
    /// When the current press started (None if released)
    press_time: Option<Instant>,
    /// When the last potential tap occurred (for double-tap detection)
    pending_tap_time: Option<Instant>,
    /// Whether we've transitioned to "held" state
    is_held: bool,
    /// Last time we emitted a hold tick
    last_tick_time: Option<Instant>,
}

/// Main gesture detection engine
pub struct GestureDetector {
    config: GestureConfig,
    key_states: HashMap<u8, KeyGestureState>,
}

impl GestureDetector {
    pub fn new(config: GestureConfig) -> Self {
        info!(
            long_press_ms = %config.long_press_threshold.as_millis(),
            double_tap_ms = %config.double_tap_window.as_millis(),
            tick_interval_ms = %config.hold_tick_interval.as_millis(),
            "Gesture detector initialized"
        );

        Self {
            config,
            key_states: HashMap::new(),
        }
    }

    /// Process a raw key event and return any detected gestures
    #[instrument(skip(self), fields(key = %event.key, pressed = %event.pressed))]
    pub fn process_event(&mut self, event: &RawKeyEvent) -> Vec<Gesture> {
        let mut gestures = Vec::new();
        let state = self.key_states.entry(event.key).or_default();

        if event.pressed {
            // Key pressed
            trace!("Key pressed, starting timing");
            state.press_time = Some(event.timestamp);
            state.is_held = false;
            state.last_tick_time = None;
        } else {
            // Key released
            if let Some(press_time) = state.press_time.take() {
                let duration = event.timestamp.duration_since(press_time);

                if state.is_held {
                    // Was in hold state - emit hold end
                    debug!(
                        duration_ms = %duration.as_millis(),
                        "Hold ended"
                    );
                    gestures.push(Gesture::HoldEnd {
                        key: event.key,
                        total: duration,
                    });
                } else if duration >= self.config.long_press_threshold {
                    // Long press (pressed past threshold but not ticking as hold)
                    debug!(
                        duration_ms = %duration.as_millis(),
                        "Long press detected"
                    );
                    gestures.push(Gesture::LongPress {
                        key: event.key,
                        duration,
                    });
                    // Clear pending tap since this was a long press
                    state.pending_tap_time = None;
                } else {
                    // Short press - check for double-tap
                    if let Some(pending_time) = state.pending_tap_time.take() {
                        let interval = event.timestamp.duration_since(pending_time);
                        if interval < self.config.double_tap_window {
                            // Double tap!
                            debug!(
                                interval_ms = %interval.as_millis(),
                                "Double tap detected"
                            );
                            gestures.push(Gesture::DoubleTap {
                                key: event.key,
                                interval,
                            });
                        } else {
                            // Too slow for double-tap, emit the pending tap
                            // and start new pending tap
                            trace!("Pending tap expired, emitting tap");
                            gestures.push(Gesture::Tap { key: event.key });
                            state.pending_tap_time = Some(event.timestamp);
                        }
                    } else {
                        // First potential tap - defer emission
                        trace!("Starting pending tap timer");
                        state.pending_tap_time = Some(event.timestamp);
                    }
                }

                state.is_held = false;
            } else {
                warn!("Release without matching press");
            }
        }

        gestures
    }

    /// Called periodically to emit hold ticks and finalize deferred taps
    #[instrument(skip(self), level = "trace")]
    pub fn tick(&mut self, now: Instant) -> Vec<Gesture> {
        let mut gestures = Vec::new();

        for (key, state) in &mut self.key_states {
            // Handle held keys
            if let Some(press_time) = state.press_time {
                let held_for = now.duration_since(press_time);

                // Transition to held state
                if !state.is_held && held_for >= self.config.long_press_threshold {
                    state.is_held = true;
                    debug!(key = %key, "Hold started");
                    gestures.push(Gesture::HoldStart { key: *key });
                }

                // Emit hold ticks
                if state.is_held {
                    let should_tick = state.last_tick_time
                        .map(|t| now.duration_since(t) >= self.config.hold_tick_interval)
                        .unwrap_or(true);

                    if should_tick {
                        trace!(key = %key, held_ms = %held_for.as_millis(), "Hold tick");
                        gestures.push(Gesture::HoldTick { key: *key, held_for });
                        state.last_tick_time = Some(now);
                    }
                }
            }

            // Finalize pending taps after double-tap window expires
            if let Some(pending_time) = state.pending_tap_time {
                if state.press_time.is_none() && 
                   now.duration_since(pending_time) >= self.config.double_tap_window {
                    trace!(key = %key, "Pending tap finalized");
                    gestures.push(Gesture::Tap { key: *key });
                    state.pending_tap_time = None;
                }
            }
        }

        gestures
    }

    /// Reset all state (e.g., on device reconnect)
    pub fn reset(&mut self) {
        info!("Gesture detector state reset");
        self.key_states.clear();
    }

    /// Get current config
    pub fn config(&self) -> &GestureConfig {
        &self.config
    }
}
