#[cfg(test)]
mod tests {
    use super::*;

    fn make_event(key: u8, pressed: bool, offset_ms: u64) -> RawKeyEvent {
        RawKeyEvent {
            key,
            pressed,
            timestamp: Instant::now() + Duration::from_millis(offset_ms),
        }
    }

    #[test]
    fn test_single_tap() {
        let mut detector = GestureDetector::new(GestureConfig::default());
        let base = Instant::now();

        // Press
        let gestures = detector.process_event(&RawKeyEvent {
            key: 0,
            pressed: true,
            timestamp: base,
        });
        assert!(gestures.is_empty());

        // Quick release (100ms)
        let gestures = detector.process_event(&RawKeyEvent {
            key: 0,
            pressed: false,
            timestamp: base + Duration::from_millis(100),
        });
        assert!(gestures.is_empty()); // Tap is deferred

        // Tick after double-tap window
        let gestures = detector.tick(base + Duration::from_millis(400));
        assert_eq!(gestures.len(), 1);
        assert!(matches!(gestures[0], Gesture::Tap { key: 0 }));
    }

    #[test]
    fn test_double_tap() {
        let mut detector = GestureDetector::new(GestureConfig::default());
        let base = Instant::now();

        // First tap
        detector.process_event(&RawKeyEvent { key: 0, pressed: true, timestamp: base });
        detector.process_event(&RawKeyEvent { key: 0, pressed: false, timestamp: base + Duration::from_millis(50) });

        // Second tap within window (200ms after first release)
        detector.process_event(&RawKeyEvent { key: 0, pressed: true, timestamp: base + Duration::from_millis(150) });
        let gestures = detector.process_event(&RawKeyEvent { key: 0, pressed: false, timestamp: base + Duration::from_millis(200) });

        assert_eq!(gestures.len(), 1);
        assert!(matches!(gestures[0], Gesture::DoubleTap { key: 0, .. }));
    }

    #[test]
    fn test_long_press() {
        let mut detector = GestureDetector::new(GestureConfig::default());
        let base = Instant::now();

        // Press
        detector.process_event(&RawKeyEvent { key: 0, pressed: true, timestamp: base });

        // Release after threshold (1 second)
        let gestures = detector.process_event(&RawKeyEvent {
            key: 0,
            pressed: false,
            timestamp: base + Duration::from_millis(1000),
        });

        assert_eq!(gestures.len(), 1);
        assert!(matches!(gestures[0], Gesture::LongPress { key: 0, .. }));
    }

    #[test]
    fn test_hold_with_ticks() {
        let config = GestureConfig {
            hold_tick_interval: Duration::from_millis(100),
            ..Default::default()
        };
        let mut detector = GestureDetector::new(config);
        let base = Instant::now();

        // Press
        detector.process_event(&RawKeyEvent { key: 0, pressed: true, timestamp: base });

        // Tick after threshold - should get HoldStart
        let gestures = detector.tick(base + Duration::from_millis(850));
        assert!(gestures.iter().any(|g| matches!(g, Gesture::HoldStart { .. })));

        // Tick again - should get HoldTick
        let gestures = detector.tick(base + Duration::from_millis(950));
        assert!(gestures.iter().any(|g| matches!(g, Gesture::HoldTick { .. })));

        // Release - should get HoldEnd
        let gestures = detector.process_event(&RawKeyEvent {
            key: 0,
            pressed: false,
            timestamp: base + Duration::from_millis(1100),
        });
        assert!(gestures.iter().any(|g| matches!(g, Gesture::HoldEnd { .. })));
    }
